import { Component, OnInit } from '@angular/core';
import { IonHeader, IonToolbar, IonTitle, IonContent, IonCard, IonCardHeader, IonCardTitle, IonCardSubtitle, IonCardContent, IonButton, IonGrid, IonRow, IonCol } from '@ionic/angular/standalone';
import { PresupuestoService } from '../api/presupuesto-service';
import { Result } from '../model/Result.model';
import { jsPDF } from 'jspdf';

@Component({
  selector: 'app-home',
  templateUrl: 'home.page.html',
  styleUrls: ['home.page.scss'],
  imports: [IonHeader, IonToolbar, IonTitle, IonContent, IonCard, IonCardHeader, IonCardTitle, IonCardSubtitle, IonCardContent, IonButton, IonGrid, IonRow, IonCol],
})
export class HomePage implements OnInit {
  result?: Result[];

  constructor(private presupuestoService: PresupuestoService) { }

  ngOnInit(): void {
    this.presupuestoService.getAll().subscribe({
      next: (data) => {
        this.result = data;
      },
      error: (err) => console.error('Error al conectar con Spring Boot', err)
    })
  }

  async generatePdf(id: number) {
    let selected: Result;
    await this.presupuestoService.getById(id).subscribe({
      next: (data) => {
        selected = data;
        let logo = "";

        const doc = new jsPDF('p', 'pt', 'a4');
        let trCounter = 0;
        let element = `
        <div style="font-family: 'Arial', sans-serif; color: black; font-size: 12px; width: 465px; margin: 16px;">
          <table style="border-collapse: collapse; margin-left: 77px; margin-bottom: 40px;">
            <tr>
              <td><h3 style="margin: 0; padding: 0; font-weight: bold; font-size: 14px;">Presupuesto</h3></td>
            </tr>
            <tr>
              <td><h4 style="margin: 0; padding: 0; font-weight: bold; font-size: 12px; margin-top: 5px;">Orange Empresas</h4></td>
            </tr>
          </table>
          <table style="border: 1px solid black;  width: 465px;">
            <thead style="background-color: grey; color: white; text-align: left; text-justify: center;">
              <tr>
                <th width="15%">CANTIDAD</th>
                <th width="70%">DESCRIPCIÓN</th>
                <th width="15%">IMPORTE</th>
              </tr>
            </thead>
            <tbody>
        `;

        if (selected.presupuesto.tarifa?.nombre != null) {
          trCounter++;
          element += `
          <tr style="background-color: ${trCounter % 2 == 0 ? 'lightgrey;' : 'white;'}">
            <td style="text-align: center;">1</td>
            <td>
            ${selected.presupuesto.tarifa?.nombre} ${selected.presupuesto.tarifa.lineasMoviles > 1 ? selected.presupuesto.tarifa.lineasMoviles + ' líneas móviles' : selected.presupuesto.tarifa.lineasMoviles + ' línea móvil'} con ${selected.presupuesto.tarifa.llamadasMovil == 'Ilimitafas' ? ' llamadas ilimitadas' : selected.presupuesto.tarifa.llamadasMovil}, ${selected.presupuesto.tarifa.gbMovil == 'Ilimitados' ? 'GBs ilimitados' : 'selected.presupuesto.tarifa.gbMovil'} y fibra de ${selected.presupuesto.fibra?.nombre};
            </td>
            <td style="text-align: right;">${selected.presupuesto.tarifa.precio.toFixed(2).toString().replace('.', ',')}€</td>
          </tr>
          `;
          if (selected.presupuesto.descuento?.porciento != null && selected.presupuesto.descuento?.porciento > 0) {
            trCounter++;
            element += `
            <tr style="background-color: ${trCounter % 2 == 0 ? 'lightgrey;' : 'white;'}">
              <td style="text-align: center;">1</td>
              <td>Descuento ${selected.presupuesto.descuento.porciento}%</td>
              <td style="text-align: right;">-${((selected.presupuesto.tarifa?.precio * selected.presupuesto.descuento.porciento) / 100).toFixed(2).toString().replace('.', ',')}€</td>
            </tr>
            `;
          }
        }
        if (selected.presupuesto.centralita?.nombre != null) {
          trCounter++;
          element += `
          <tr style="background-color: ${trCounter % 2 == 0 ? 'lightgrey;' : 'white;'}">
              <td style="text-align: center;">1</td>
              <td>Centralita ${selected.presupuesto.centralita.nombre}</td>
              <td style="text-align: right;">${selected.presupuesto.centralita.precio.toFixed(2).toString().replace('.', ',')}€</td>
          </tr>
          `;
        }
        if (selected.presupuesto.packFutbol?.nombre != null) {
          trCounter++;
          element += `
          <tr style="background-color: ${trCounter % 2 == 0 ? 'lightgrey;' : 'white;'}">
            <td style="text-align: center;">1</td>
            <td>${selected.presupuesto.packFutbol.nombre}</td>
            <td style="text-align: right;">${selected.presupuesto.packFutbol.precio.toFixed(2).toString().replace('.', ',')}€</td>
          </tr>
          `;
        }

        if (selected.lineas != null) {
          let lineaRow = '';
          selected.lineas.forEach(linea => {
            trCounter++;
            lineaRow += `
            <tr style="background-color: ${trCounter % 2 == 0 ? 'lightgrey;' : 'white;'}">
              <td style="text-align: center;">${linea.cantidad}</td>
              <td>${linea.lineaAdicional.nombre}</td>
              <td style="text-align: right;">${linea.lineaAdicional.precio.toFixed(2).toString().replace('.', ',')}€</td>
            </tr>
            `;
          });
          element += lineaRow;
        }

        element += `
        <tr style="border-top: 1px solid black;">
          <td colspan=2 style="font-weight: bold; text-align: right;">Total:</td>
          <td style="text-align: right;">${selected.total.toFixed(2).toString().replace('.', ',')}€</td>
        </tr>
        </tbody>
        </table>
        `;

        if (selected.serviciosAdicionales.id > 0) {
          element += `
          <div style="margin: 0; padding: 0; margin-top: 20px;">
          <p style="margin: 0; padding: 0;">Roaming: ${selected.serviciosAdicionales.roaming}.</p>
          ${selected.serviciosAdicionales.internacional != null ? '<p style="margin: 0; padding: 0;">Llamadas internacionales: ' + selected.serviciosAdicionales.internacional + '.</p>' : ''}
          ${selected.serviciosAdicionales.legalitas ? '<p style="margin: 0; padding: 0;">Legálitas Protección Jurídica Negocios Orange.</p>' : ''}
          ${selected.serviciosAdicionales.could ? '<p style="margin: 0; padding: 0;">Cloud y Protección Dispositivos.</p>' : ''}
          ${selected.serviciosAdicionales.ciberProteccion ? '<p style="margin: 0; padding: 0;">Ciber Protección Red Móvil.</p>' : ''}
          ${selected.serviciosAdicionales.atencionPersonalizada ? '<p style="margin: 0; padding: 0;">Atención personalizada.</p>' : ''}
          ${selected.serviciosAdicionales.centralita != null ? '<p style="margin: 0; padding: 0;">Centralita Negocio: ' + selected.serviciosAdicionales.centralita + '.</p>' : ''}
          ${selected.serviciosAdicionales.numeroBeneficios > 0 ? '<p style="margin: 0; padding: 0;">' + (selected.serviciosAdicionales.numeroBeneficios > 1 ? selected.serviciosAdicionales.numeroBeneficios + ' beneficios a elegir' : selected.serviciosAdicionales.numeroBeneficios + ' beneficio a elegir') + (selected.serviciosAdicionales.descuentoBeneficios != null ? ' con ' + selected.serviciosAdicionales.descuentoBeneficios + '% de decuento' : '') + '.</p>' : ''}
          </div>
          `;
        }


        element += `
        </div>
        `;

        let fecha = new Date();
        let nombreFichero = selected.presupuesto.nombre + '_' + fecha.getFullYear() + '-' + (fecha.getMonth() + 1) + '-' + fecha.getDate() + '.pdf';
        doc.html(element, {
          callback: (doc) => {
            let width = 45;
            let height = width * 0.455;
            doc.addImage(logo, 'PNG', 82, 72, width, height);
            doc.save(nombreFichero);
          },
          x: 10,
          y: 10,
          autoPaging: 'text',
          margin: [40, 40, 40, 40]
        }
        );
      },
      error: (err) => console.error('Error al conectar con Spring Boot', err)
    })
  }
}
